#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int R1, R2, D1, D2;
        scanf("%d %d", &R1, &R2);
        scanf("%d %d", &D1, &D2);
        int final1 = R1 + D1;
        int final2 = R2 + D2;
        if (final1 > final2) {
            printf("Dominater\n");
        } else {
            printf("Everule\n");
        }
    }
    return 0;
}

