import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        R1 = int(next(it)); R2 = int(next(it))
        D1 = int(next(it)); D2 = int(next(it))
        if R1 + D1 > R2 + D2:
            out_lines.append("Dominater")
        else:
            out_lines.append("Everule")
    sys.stdout.write("\n".join(out_lines))

if __name__ == "__main__":
    solve()

